ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT ?name WHERE {
  ?staff a :Staff .
  ?staff p:name ?name .
  ?staff p:Role ?role_w .
  ?staff p:Role ?role_w2 .
  ?staff p:Language ?language_w .
  FILTER((STR(?role_w) = "Chef" || (STR(?role_w2) = "Server" && STR(?language_w) = "English")))
} }
  high: { SELECT ?name WHERE {
  ?staff a :Staff .
  ?staff p:name ?name .
  ?staff p:Role ?role_w .
  ?staff p:Role ?role_w2 .
  ?staff p:Language ?language_w .
  FILTER((((STR(?role_w) = "Chef" || STR(?role_w2) = "Server")) && STR(?language_w) = "English"))
} }
}
